const SettingsSubstrate = (function() {
    'use strict';


    const STORAGE_KEY = 'kensgames_settings';


    const DEFAULTS = {

        musicEnabled: true,
        musicVolume: 0.5,
        sfxEnabled: true,
        sfxVolume: 0.7,


        cameraMode: 'manual',
        cameraAngle: 45,
        cameraDistance: 'medium',


        theme: 'default',
        showFPS: false,
        highQuality: true,


        showHints: true,
        confirmMoves: false,
        autoEndTurn: true,


        reducedMotion: false,
        highContrast: false,
        largeText: false
    };


    let _settings = null;


    const _listeners = new Map();


    function load() {
        try {
            const stored = localStorage.getItem(STORAGE_KEY);
            const parsed = stored ? JSON.parse(stored) : {};
            _settings = { ...DEFAULTS, ...parsed };
        } catch (e) {
            console.warn('[SettingsSubstrate] Failed to load settings:', e);
            _settings = { ...DEFAULTS };
        }
        return _settings;
    }


    function save() {
        try {

            const toStore = {};
            for (const key in _settings) {
                if (_settings[key] !== DEFAULTS[key]) {
                    toStore[key] = _settings[key];
                }
            }
            localStorage.setItem(STORAGE_KEY, JSON.stringify(toStore));
        } catch (e) {
            console.warn('[SettingsSubstrate] Failed to save settings:', e);
        }
    }


    function get(key) {
        if (!_settings) load();
        return _settings.hasOwnProperty(key) ? _settings[key] : DEFAULTS[key];
    }


    function set(key, value) {
        if (!_settings) load();
        const oldValue = _settings[key];
        _settings[key] = value;
        save();


        if (_listeners.has(key)) {
            _listeners.get(key).forEach(fn => fn(value, oldValue, key));
        }
        if (_listeners.has('*')) {
            _listeners.get('*').forEach(fn => fn(value, oldValue, key));
        }
    }


    function onChange(key, callback) {
        if (!_listeners.has(key)) {
            _listeners.set(key, []);
        }
        _listeners.get(key).push(callback);


        return () => {
            const list = _listeners.get(key);
            const idx = list.indexOf(callback);
            if (idx >= 0) list.splice(idx, 1);
        };
    }


    function getAll() {
        if (!_settings) load();
        return { ..._settings };
    }


    function reset() {
        _settings = { ...DEFAULTS };
        save();
    }


    return {
        load,
        save,
        get,
        set,
        onChange,
        getAll,
        reset,
        DEFAULTS
    };
})();


if (typeof module !== 'undefined' && module.exports) {
    module.exports = SettingsSubstrate;
}
